classdef AnalyticShootingAdapter < lmz.shooting.SectionSimulationAdapter
    %ANALYTICSHOOTINGADAPTER Affine one-state segment map for unit tests.
    methods
        function value=simulateSegment(~,request,~,includeSimulation)
            controls=request.ControlParameters;
            initial=request.StartNode.SectionCoordinates(1);
            terminal=controls.Gain*initial+controls.Offset;
            simulation=[];
            if includeSimulation
                simulation=struct('Time',[0;1], ...
                    'State',[initial;terminal], ...
                    'SegmentIndex',request.Segment.Index);
            end
            physical=isfinite(terminal);
            if isfield(request.Configuration,'InvalidSegment')&& ...
                    request.Configuration.InvalidSegment==request.Segment.Index
                physical=false;
            end
            value=struct('TerminalState',terminal, ...
                'TerminalCoordinates',terminal, ...
                'ContactResiduals',zeros(0,1), ...
                'SectionResidual',zeros(0,1), ...
                'EnergyResidual',zeros(0,1), ...
                'Crossing',struct('Accepted',true,'Grazing',false), ...
                'Simulation',simulation,'PhysicalValidity',physical, ...
                'Diagnostics',struct('EventOrderValid',true, ...
                'Map','affine-one-state-v1'));
        end
    end
end
